// Startup: register DbContext as scoped
builder.Services.AddDbContext<AppDbContext>(options =>
    options.UseNpgsql(connectionString));

// Service layer: encapsulates domain logic
public interface IUserService
{
    Task<UserDto> CreateAsync(CreateUserDto dto, CancellationToken ct);
    Task<UserDto?> GetByIdAsync(int id, CancellationToken ct);
}

public class UserService(AppDbContext db, IPasswordHasher<User> hasher) : IUserService
{
    public async Task<UserDto> CreateAsync(CreateUserDto dto, CancellationToken ct)
    {
        var user = new User { Email = dto.Email, PasswordHash = hasher.Hash(dto.Password) };
        db.Users.Add(user);
        await db.SaveChangesAsync(ct);
        return new UserDto(user.Id, user.Email);
    }

    public async Task<UserDto?> GetByIdAsync(int id, CancellationToken ct)
    {
        var user = await db.Users.FindAsync(new object[] { id }, cancellationToken: ct);
        return user == null ? null : new UserDto(user.Id, user.Email);
    }
}

// Controller: stays thin
[ApiController]
[Route("api/[controller]")]
public class UsersController(IUserService users) : ControllerBase
{
    [HttpPost]
    public async Task<IActionResult> Create(CreateUserDto dto, CancellationToken ct)
    {
        var result = await users.CreateAsync(dto, ct);
        return CreatedAtAction(nameof(GetById), new { id = result.Id }, result);
    }

    [HttpGet("{id}")]
    public async Task<ActionResult<UserDto>> GetById(int id, CancellationToken ct)
    {
        var user = await users.GetByIdAsync(id, ct);
        return user == null ? NotFound() : Ok(user);
    }
}

// DTOs as records: immutable, strongly typed
public record UserDto(int Id, string Email);
public record CreateUserDto(string Email, string Password);

public class UsersController(AppDbContext db) : ControllerBase
{
    [HttpGet("{id}")]
    public async Task<IActionResult> GetById(int id)
    {
        var user = await db.Users.FindAsync(id);  // ❌ no service layer
        return user == null ? NotFound() : Ok(user);  // ❌ returns tracked entity
    }
}

public class ProblemDetailsHandler : IExceptionHandler
{
    public async ValueTask<bool> TryHandleAsync(
        HttpContext ctx, Exception ex, CancellationToken ct)
    {
        var pd = ex switch
        {
            NotFoundException nf => new ProblemDetails
            {
                Status = 404,
                Title = "Not Found",
                Detail = nf.Message,
                Type = "https://example.com/problems/not-found"
            },
            ValidationException ve => new ProblemDetails
            {
                Status = 422,
                Title = "Validation Failed",
                Detail = ve.Message,
                Type = "https://example.com/problems/validation"
            },
            _ => new ProblemDetails
            {
                Status = 500,
                Title = "Internal Server Error",
                Type = "https://example.com/problems/server-error"
            }
        };
        ctx.Response.StatusCode = pd.Status!.Value;
        await ctx.Response.WriteAsJsonAsync(pd, ct);
        return true;
    }
}

// Program.cs
builder.Services.AddProblemDetails();
builder.Services.AddExceptionHandler<ProblemDetailsHandler>();
app.UseExceptionHandler();

[Mapper]
public partial class UserMapper
{
    public partial UserDto ToDto(User user);
    public partial User ToEntity(CreateUserDto dto);
}

// Usage in service
var userDto = _mapper.ToDto(user);

[Collection("Database collection")]
public class UserApiTests : IAsyncLifetime
{
    private readonly WebApplicationFactory<Program> factory;
    private HttpClient client;

    public UserApiTests()
    {
        factory = new WebApplicationFactory<Program>()
            .WithWebHostBuilder(builder =>
            {
                builder.ConfigureServices(services =>
                {
                    // Replace with test database
                    services.Remove(services.Single(d => d.ServiceType == typeof(DbContextOptions<AppDbContext>)));
                    services.AddDbContext<AppDbContext>(options =>
                        options.UseNpgsql(testConnectionString));
                });
            });
    }

    public async Task InitializeAsync()
    {
        client = factory.CreateClient();
        using (var scope = factory.Services.CreateScope())
        {
            var db = scope.ServiceProvider.GetRequiredService<AppDbContext>();
            await db.Database.MigrateAsync();
        }
    }

    public Task DisposeAsync() => factory.DisposeAsync().AsTask();

    [Fact]
    public async Task CreateUser_ReturnsCreatedAtAction()
    {
        var response = await client.PostAsJsonAsync("/api/users",
            new { email = "test@example.com", password = "secret" });
        Assert.Equal(HttpStatusCode.Created, response.StatusCode);
    }
}

// Multi-step write with transaction
public async Task TransferAsync(int fromId, int toId, decimal amount, CancellationToken ct)
{
    await using var transaction = await db.Database.BeginTransactionAsync(ct);
    try
    {
        var from = await db.Accounts.FindAsync(new object[] { fromId }, cancellationToken: ct);
        from.Balance -= amount;
        var to = await db.Accounts.FindAsync(new object[] { toId }, cancellationToken: ct);
        to.Balance += amount;
        await db.SaveChangesAsync(ct);
        await transaction.CommitAsync(ct);
    }
    catch
    {
        await transaction.RollbackAsync(ct);
        throw;
    }
}

// Keyset pagination
public async Task<List<UserDto>> GetUsersAsync(int? afterId, CancellationToken ct)
{
    var query = db.Users
        .Where(u => afterId == null || u.Id > afterId)
        .OrderBy(u => u.Id)
        .Take(20);
    var users = await query.ToListAsync(ct);
    return users.Select(u => new UserDto(u.Id, u.Email)).ToList();
}
